mapper.select:
SELECT o.*, c.customer_name, c.contact_phone AS customer_phone, e.equipment_name, e.specification AS equipment_spec, r.role_name AS creator_name FROM orders o LEFT JOIN customers c ON o.customer_id = c.customer_id LEFT JOIN equipment e ON o.equipment_id = e.equipment_id LEFT JOIN sys_user_role r ON o.created_by = r.user_id WHERE o.deleted = false
AND o.order_type = #{orderType}
AND o.order_status = #{orderStatus}
AND o.delivery_date >= #{startDate}
AND o.delivery_date <= #{endDate}
AND ( o.order_id::text ILIKE CONCAT('%', #{keyword}, '%') OR c.customer_name ILIKE CONCAT('%', #{keyword}, '%') OR e.equipment_code ILIKE CONCAT('%', #{keyword}, '%') )
ORDER BY o.last_modified_at DESC

SELECT o.*, c.customer_name, c.contact_phone AS customer_phone, e.equipment_name, e.specification AS equipment_spec, r.role_name AS creator_name FROM orders o LEFT JOIN customers c ON o.customer_id = c.customer_id LEFT JOIN equipment e ON o.equipment_id = e.equipment_id LEFT JOIN sys_user_role r ON o.created_by = r.user_id WHERE o.order_id IN
#{id, typeHandler=com.ordermanager.handler.UUIDTypeHandler}
AND o.deleted = false
